def trai():
    if song:
        xe_em.setx(max(xe_em.xcor() - 100, -150))

def phai():
    if song:
        xe_em.setx(min(xe_em.xcor() + 100, 150))

man_hinh.listen()
man_hinh.onkey(trai, "Left")
man_hinh.onkey(phai, "Right")

def cap_nhat():
    global diem, song
    if not song:
        return
    for xe in xe_doi[:]:
        xe.sety(xe.ycor() - 6)
        if xe.ycor() < -300:
            xe.hideturtle()
            xe_doi.remove(xe)
            diem += 10
            ve_bang()
    man_hinh.update()
    man_hinh.ontimer(cap_nhat, 40)
